  "corrected_code": "package org.example.app.banji;

import com.alibaba.fastjson.JSON;
import org.example.app.db.DB;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.sql.Connection;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.sql.Statement;
import java.util.ArrayList;
import java.util.List;

public class Sample009 {
    private static final Logger logger = LoggerFactory.getLogger(Sample009.class);

    public String selectAll() {
        List<BanjiBean> list = new ArrayList<>();
        String sql = "SELECT id, banji_name, zhuanye, fudaoyuan, renshu FROM t_banji";

        try (Connection connection = DB.getConnetion();
             Statement statement = connection.createStatement();
             ResultSet resultSet = statement.executeQuery(sql)) {

            while (resultSet.next()) {
                BanjiBean bean = new BanjiBean();
                bean.setId(resultSet.getInt("id"));
                bean.setBanji_name(resultSet.getString("banji_name"));
                bean.setZhuanye(resultSet.getString("zhuanye"));
                bean.setFudaoyuan(resultSet.getString("fudaoyuan"));
                bean.setRenshu(resultSet.getInt("renshu"));
                list.add(bean);
            }

            return JSON.toJSONString(list);

        } catch (SQLException e) {
            logger.error("Database error while fetching banji records", e);
            return "{\"error\":\"Database error occurred\"}";
        } catch (Exception e) {
            logger.error("Unexpected error in selectAll", e);
            return "{\"error\":\"Internal server error\"}";
        }
    }
}"
